            headers:{'Content-Type':'application/json'},
            method: "PUT",
            body: JSON.stringify(empdata)
           }
               
           fetch(url,postoption)
           .then(response => response.json())
           .then(empinfo =>{
            alert(fullname + "Updated Successfully !!")
            window.location.href = "#/employee";
           })
     }

     const showdetails = (id) =>{
        let url = "http://localhost:3333/user"+id;
        fetch(url)
        .then(responsedata => responsedata.json())
        .then(data => {
           
        })
     }

    useEffect(()=>{
        getusers();
    },[1])

    return (
        <section>
        <HashRouter>
            <nav className="navbar navbar-expand-lg bg-dark sticky-top p-3">
            <div className="container-fluid">
              <a className="navbar-brand text-white" href="#">  User Management System</a>
              <button className="navbar-toggler" type="button" data-bs-toggle="collapse" data-bs-target="#navbarSupportedContent" aria-controls="navbarSupportedContent" aria-expanded="false" aria-label="Toggle navigation">
                <span className="navbar-toggler-icon"></span>
              </button>
              <div className="collapse navbar-collapse" id="navbarSupportedContent">
                <ul className="navbar-nav ms-auto mb-2 mb-lg-0">
                    {/* by using ms-auto ul will be shifted to right and by writing mx-auto ul will be shifted to middle */}
                 
                    <li className="nav-item me-5">
                 <Link className="nav-link btn btn-warning text-white" to="/adduser"><i className='fa fa-plus'></i>  Add User</Link>
                 </li>

                  <li className="nav-item me-5">
                  <label className="text-danger" onClick={logout}> Welcome - {localStorage.getItem("fullname") } Logout <i className="fa fa-power-off"></i>  </label>
                  </li>
    
                  <li className="nav-item me-5">
                    
                  </li>
                </ul>
                
              </div>
            </div>
          </nav>
           
      <Routes>
      <Route exact path="/adduser" element={<Adduser />} />
      </Routes>
      </HashRouter>
     

      <div className="container mt-4">
        <div className="row">
     {
           
          userlist.map((user, index) => {
            // it cheks what user type in search box include in the product or not
            return (
                <div class="col-lg-3 mb-4" key={index} >
                   <div class="card" onClick={showdetails(user.id)}>
                    <div class="card-header bg-primary text-white text-right">
